match (self, other) {
    (Self::Alt(alts), other) | (other, Self::Alt(alts)) if alts.len() == 0 => other,
    (Self::Alt(mut lhs), Self::Alt(rhs)) => {
        lhs.extend(rhs);
        Self::Alt(lhs)
    }
    (Self::Alt(mut alts), alt) | (alt, Self::Alt(mut alts)) => {
        alts.push(alt);
        Self::Alt(alts)
    }
    (lhs, rhs) => Self::Alt(vec![lhs, rhs]),
}

if power2 <= 0 {
    if -power2 + 1 >= 64 {
        // Have more than 64 bits below the minimum exponent, must be 0.
        return fp_zero;
    }
    // Have a subnormal value.
    mantissa >>= -power2 + 1;
    mantissa += mantissa & 1;
    mantissa >>= 1;
    power2 = (mantissa >= (1_u64 << F::SIG_BITS)) as i32;
    return BiasedFp { m: mantissa, p_biased: power2 };
}

